function n(r){const t=Number(r||0);return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(t)}function a(r){return new Intl.NumberFormat("en-US").format(Number(r||0))}function o(r){return`${Number(r||0).toFixed(1)}%`}function m(r){return r?new Intl.DateTimeFormat("en-US",{month:"short",day:"numeric",year:"numeric"}).format(new Date(r)):""}function u(r=""){return r.split(" ").filter(Boolean).slice(0,2).map(t=>{var e;return(e=t[0])==null?void 0:e.toUpperCase()}).join("")}export{n as a,o as b,m as c,a as f,u as i};
